const ids = String($env.GHL_LOCATION_IDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (ids.length === 0) throw new Error('GHL_LOCATION_IDS no configurado');
return ids.map(location_id => ({ json: { location_id } }));

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const stateRow    = $input.first().json;
const location_id = stateRow.location_id;
const lastSynced  = stateRow.last_synced_at;
const lastCursor  = stateRow.last_cursor;
const apiKey      = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let allAppts   = [];
let nextCursor = lastCursor || null;
let page = 0;
const MAX_PAGES = 100;

while (page < MAX_PAGES) {
  const url = new URL('https://services.leadconnectorhq.com/calendars/events');
  url.searchParams.set('locationId', location_id);
  url.searchParams.set('limit', '100');
  if (lastSynced && !nextCursor) url.searchParams.set('startTime', lastSynced);
  if (nextCursor) url.searchParams.set('startAfter', nextCursor);

  let resp;
  let retries = 0;
  while (retries < 5) {
    try {
      resp = await fetch(url.toString(), {
        headers: { 'Authorization': 'Bearer ' + apiKey, 'Version': '2021-04-15' }
      });
      if (resp.status === 429) { await sleep(Math.pow(2, retries) * 1000); retries++; continue; }
      break;
    } catch (err) {
      if (retries >= 4) throw err;
      await sleep(Math.pow(2, retries) * 1000);
      retries++;
    }
  }
  if (!resp.ok) throw new Error('GHL API error ' + resp.status + ' appointments');

  const data = await resp.json();
  const appts = data.events || data.appointments || [];
  allAppts = allAppts.concat(appts);
  nextCursor = data.meta?.startAfter || null;
  if (!nextCursor || appts.length === 0) break;
  page++;
  await sleep(130);
}

return [{ json: { location_id, appointments: allAppts, next_cursor: nextCursor } }];

const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;
function cleanStr(val, maxLen) { if (!val) return null; const s = String(val).trim().substring(0, maxLen); return s.length > 0 ? s : null; }
function validateGHLId(val) { if (!val) return null; const s = String(val).trim(); return REGEX_GHL_ID.test(s) ? s : null; }
function parseISODate(val) { if (!val) return null; const ts = Date.parse(String(val)); return isNaN(ts) ? null : new Date(ts).toISOString(); }

const { location_id, appointments, next_cursor } = $input.first().json;

const cleaned = appointments
  .filter(a => REGEX_GHL_ID.test(String(a.id || a.appointmentId || '').trim()))
  .map(a => ({
    appointment_id:   String(a.id || a.appointmentId).trim(),
    contact_id:       validateGHLId(a.contactId || a.contact_id),
    location_id,
    calendar_id:      validateGHLId(a.calendarId),
    title:            cleanStr(a.title, 500),
    status:           cleanStr(a.appointmentStatus || a.status, 30),
    start_time:       parseISODate(a.startTime),
    end_time:         parseISODate(a.endTime),
    assigned_user_id: validateGHLId(a.assignedUserId || a.userId),
    notes:            a.notes ? String(a.notes).substring(0, 5000) : null,
    address:          cleanStr(a.address, 500),
    ghl_created_at:   parseISODate(a.dateAdded  || a.createdAt),
    ghl_updated_at:   parseISODate(a.dateUpdated || a.updatedAt),
    synced_at:        new Date().toISOString()
  })).filter(a => a.contact_id);

return [{ json: { location_id, appointments: cleaned, next_cursor, total: cleaned.length } }];

